/* adm-system-accessControl-sql-oracle.xml - selectAccessControl */ SELECT ID, IPADDR, MACADDR, PRDCTTYPE, DESCRPT, INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY, DELYN FROM TADMIN_MST_ACTL WHERE 1=1
