mapper.update:
/* adm-system-accessControl-sql-oracle.xml - saveAccessControlInfo */
/* Converted from: MERGE INTO TADMIN_MST_ACTL -- UPDATE+INSERT pattern */
UPDATE TADMIN_MST_ACTL
   SET IPADDR = #{ipaddr},
       MACADDR = #{macaddr},
       PRDCTTYPE = #{prdcttype},
       DESCRPT = #{descrpt},
       UPDATEDATE = #{sysdate},
       UPDATEURKEY = #{surkey},
       DELYN = #{delyn}
 WHERE ID = #{id};

INSERT INTO TADMIN_MST_ACTL (
    ID, IPADDR, MACADDR, PRDCTTYPE, DESCRPT,
    INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY, DELYN
)
SELECT #{id}, #{ipaddr}, #{macaddr}, #{prdcttype}, #{descrpt},
       #{sysdate}, #{surkey}, #{sysdate}, #{surkey}, #{delyn}
 WHERE NOT EXISTS (
       SELECT 1 FROM TADMIN_MST_ACTL WHERE ID = #{id}
 )

mapper.delete:
/* adm-system-accessControl-sql-oracle.xml - deleteAccessControlInfo */
DELETE
FROM TADMIN_MST_ACTL
WHERE ID = #{id}
